import React from 'react';
import { useLocation } from 'react-router-dom';
import {
  WorkspaceTabProvider as SharedWorkspaceTabProvider,
  useWorkspaceTabs,
  useWorkspaceTabsOptional,
} from '@linm-soft-org/linm-web-common-components';
export type { WorkspaceTabProviderProps } from '@linm-soft-org/linm-web-common-components';

/**
 * Finance MFE adapter — provides `pathname` from react-router location,
 * delegates all state/tab logic to the shared WorkspaceTabProvider.
 */
export const WorkspaceTabProvider: React.FC<{
  children: React.ReactNode;
  navigate: (path: string) => void;
}> = ({ children, navigate }) => {
  const location = useLocation();
  const pathname = location.pathname + location.search;
  return (
    <SharedWorkspaceTabProvider navigate={navigate} pathname={pathname}>
      {children}
    </SharedWorkspaceTabProvider>
  );
};

export { useWorkspaceTabs, useWorkspaceTabsOptional };
