/**
 * API Error Navigation System (MFE-local copy)
 *
 * Chỉ dispatch 403/404 → navigate error page khi là GET request (load page).
 * POST/PUT/PATCH/DELETE (form actions) → vẫn show toast bình thường, không navigate.
 */

export interface ApiNavigationEvent {
  statusCode: number;
  endpoint: string;
  /** HTTP method: GET | POST | PUT | PATCH | DELETE */
  method: string;
}

export type ApiNavigationHandler = (event: ApiNavigationEvent) => void;

let _handler: ApiNavigationHandler | null = null;

export function registerApiNavigationHandler(handler: ApiNavigationHandler): void {
  _handler = handler;
}

export function unregisterApiNavigationHandler(): void {
  _handler = null;
}

export function getApiNavigationHandler(): ApiNavigationHandler | null {
  return _handler;
}
