let patched = false;

/**
 * Defer ResizeObserver callbacks to the next animation frame.
 * Prevents benign "ResizeObserver loop completed with undelivered notifications"
 * when observers read layout and trigger follow-up resizes in the same frame.
 */
export function patchResizeObserverLoopGuard(): void {
  if (patched || import.meta.env.PROD) return;
  if (typeof window === 'undefined' || typeof ResizeObserver === 'undefined') return;

  patched = true;
  const NativeResizeObserver = ResizeObserver;

  window.ResizeObserver = class PatchedResizeObserver extends NativeResizeObserver {
    constructor(callback: ResizeObserverCallback) {
      let frameId = 0;
      super((entries, observer) => {
        if (frameId) cancelAnimationFrame(frameId);
        frameId = requestAnimationFrame(() => {
          frameId = 0;
          callback(entries, observer);
        });
      });
    }
  } as typeof ResizeObserver;
}
