import { createSlice, PayloadAction } from '@reduxjs/toolkit';

interface ErpFinanceState {
  loading: boolean;
}

const erpFinanceSlice = createSlice({
  name: 'erpFinance',
  initialState: {
    loading: false,
  } as ErpFinanceState,
  reducers: {
    setLoading(state, { payload }: PayloadAction<boolean>) {
      state.loading = payload;
    },
  },
});

export const { setLoading } = erpFinanceSlice.actions;
export default erpFinanceSlice.reducer;
